using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.SignalR;
using T2ACore;

/// <summary>
/// 工具方法
/// </summary>
[ApiController]
[Route("/T2ACore/[controller]/[action]")]
[ApiExplorerSettings(GroupName = "Sys")]
public class ToolController : ControllerBase
{
    /// <summary>
    /// 通过SignalR给登录者发送消息
    /// 可用于跨服务之间发送
    /// </summary>
    /// <returns></returns>
    [HttpPost]
    public async Task<TPResponse<string>> PostMessage(
        [FromServices] IHubContext<MessageHub> msgHub,
        [FromBody] object msgContent)
    {
        var user = ScopeUser.GetUserInfo();
        if (user != null)
        {
            var group = msgHub.Clients.Group(user.Account);
            if (group != null)
            {
                await group.SendAsync("ReceiveSelfMessage", msgContent.ToString());
                return TPResponse.New("ok");
            }
            return TPResponse.New("no instance");
        }
        return TPResponse.New("no user");

    }

    /// <summary>
    /// 通过SignalR给登录者发送消息
    /// 可用于跨服务之间发送
    /// </summary>
    /// <returns></returns>
    [HttpPost]
    public async Task<TPResponse<string>> Broadcast(
        [FromServices] IHubContext<MessageHub> msgHub,
        [FromBody] object msgContent)
    {
        var user = ScopeUser.GetUserInfo();
        if (user != null)
        {
            if (Config.BaseConfig.AdminList.Contains(user.Account))
            {
                await msgHub.Clients.All.SendAsync(
                      "BroadcastMessage", msgContent.ToString());
                return TPResponse.New("ok");
            }

            return TPResponse.New("only admin allowed");
        }
        return TPResponse.New("no user");
    }

}


